import torch

def build_sft_labels(prompt_ids, answer_ids):
    # prompt 不参与损失，避免模型把梯度浪费在“复述题目”上
    ignore = torch.full_like(prompt_ids, -100)
    # 只有 answer 部分才是真正希望模型学会生成的目标
    return torch.cat([ignore, answer_ids], dim=1)

def kl_shaped_reward(rm_score, logp_policy, logp_ref, beta=0.02):
    # KL 项惩罚策略偏离 SFT 参考模型
    kl = logp_policy - logp_ref
    # 奖励不是纯 RM 分数，而是“偏好分 - 偏离代价”
    return rm_score - beta * kl.mean()

def choose_alignment_method(has_pairwise_data, needs_online_exploration, gpu_budget_tight):
    # 需要在线探索时，优先保留 RLHF 能力
    if needs_online_exploration:
        return 'RLHF'
    # 只有静态偏好集且预算紧时，DPO 往往是更现实的工程选择
    if has_pairwise_data and gpu_budget_tight:
        return 'DPO'
    # 默认回答体现“按约束选方法”，而不是教条站队
    return 'stage-wise hybrid'
